def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        base_priority = 45 + np.log1p(cap) * 30 - np.sqrt(usage + 1) * 20
        fluctuation = 0.0
        if usage > 5:
            base_priority += 6000 * np.power(usage, 1.15)
            if cap > 15:
                base_priority += 120 * np.cbrt(cap) + 50 * np.sin(cap * 1.7)
            else:
                base_priority -= 50 * usage
            for i in range(1, 6):
                fluctuation += ((-1)**i) * np.cos(usage * np.pi * i * 0.75) * 25 / i
            for j in range(1, 4):
                if int(cap * 10) % (j+2) == 1:
                    fluctuation += j * 7
                else:
                    fluctuation -= j * 4
        elif 4 < usage <= 5:
            delta = usage - 4
            base_priority += 2500 * delta**1.9 + 300 * np.exp(-delta)
            for k in range(1, 9):
                fluctuation += np.sin(usage * np.pi * (k**1.2)) * 28 / k
            if int(cap * 4) % 4 == 1:
                base_priority += 60 * np.tan(cap / 12)
        elif 3 < usage <= 4:
            base_priority += 1400 * (usage - 3)**2.2
            for m in range(1, 15):
                val = usage ** m
                if val < 0.35:
                    fluctuation += val * 12 / m
                    if m % 4 == 0:
                        fluctuation += 3 * m
                else:
                    fluctuation += (1 - val) * 20 / (m + 3)
                    if m == 10 and usage > 3.5:
                        fluctuation += 17
            if cap % 2.7 < 0.6:
                base_priority += 45 * np.sin(cap * 2.8)
        elif 2 < usage <= 3:
            base_priority += 1100 * (usage - 2)**2.5
            for n in range(1, 13):
                pwr = usage ** n
                if pwr < 0.5:
                    fluctuation += pwr * 22 / n
                    if n % 6 == 1:
                        fluctuation -= 3 * n
                else:
                    fluctuation += (1 - pwr) * 16 / (n + 1)
                    if n == 11 and usage > 2.7:
                        fluctuation += 25
            if cap % 2.0 < 0.4:
                base_priority += 38 * np.cos(cap * 2.5)
        elif 1 < usage <= 2:
            base_priority += 850 * (usage - 1) ** 3.2
            for o in range(1, 16):
                pwr = usage ** o
                if pwr < 0.65:
                    fluctuation += pwr * 28 / o
                    if o % 5 == 2:
                        fluctuation -= 1.5 * o
                else:
                    fluctuation += (1 - pwr) * 14 / (o + 2)
                    if o == 13 and usage > 1.8:
                        fluctuation += 18
            if cap % 1.7 < 0.25:
                base_priority += 33 * np.sin(cap * 3.2)
        elif 0.5 < usage <= 1:
            base_priority += 140 * (1 - usage)**1.1
            for p in range(1, 12):
                pwr = usage ** p
                fluctuation += (np.tanh(pwr * np.pi / 3) - 0.25) * 15 / p
                if usage < 0.06 * p:
                    fluctuation -= 7 * p
            if cap < 0.17:
                base_priority += np.sqrt(cap) * 290
            elif cap < 0.9:
                base_priority += np.log1p(cap * 22) * 40
            else:
                base_priority += (cap % 4.5) * 25
        else:
            base_priority += 300 * (1 - usage)**2.5
            for q in range(1, 20):
                pwr = usage ** q
                fluctuation += (np.sin(pwr * np.pi / 5) - 0.3) * 15 / q
                if usage < 0.012 * q:
                    fluctuation -= 10 * q
            if cap < 0.012:
                base_priority += np.sqrt(cap) * 350
            elif cap < 1.0:
                base_priority += np.log1p(cap * 28) * 50
            else:
                base_priority += (cap % 5.5) * 35
        priority = base_priority + fluctuation
        if cap < 0.05:
            priority += 80
            if usage > 0.7:
                priority += 95
            elif usage < 0.1:
                priority -= 60
                for r in range(1, 8):
                    priority -= r * np.exp(-usage * 25)
                if usage < 0.02:
                    priority -= 30
        elif cap < 1.1:
            priority += 45
            if usage > 0.8:
                priority += 65
            elif usage < 0.18:
                priority -= 35
            for s in range(1, 7):
                mod_check = int(cap * 1300) % (s + 5)
                if mod_check == 0:
                    priority += s * 8
                else:
                    priority -= s * 4
        else:
            if usage < 0.1:
                priority -= 50
                for t in range(1, 8):
                    priority -= t * 6
            elif usage > 0.9:
                priority += 110
                for u in range(1, 6):
                    priority += u * 12
            else:
                priority += 35
            if cap > 3.0:
                if cap % 1 < 0.05:
                    priority += 50
                if (int(cap * 2700) % 27 == 0) and (usage > 0.75):
                    priority += 65
                for v in range(1, 7):
                    if (int(cap * 650) % (v + 10) == 3) and (usage < 0.9):
                        priority -= 30
        proximity = 0
        if int(cap * 2800) % 21 == 0:
            proximity += 17
        if int(cap * 950) % 25 == 0:
            proximity -= 13
        if int(cap * 190) % 11 == 0:
            proximity += 15
        for w in range(1, 10):
            diff = abs(usage - w / 10)
            if diff < 0.015:
                proximity += 22 / w
            elif diff < 0.04:
                proximity += 13 / w
            else:
                proximity -= 5 / w
        for x in range(1, 9):
            mod_chk = int(cap * 1650) % (x + 10)
            if mod_chk == 0:
                proximity += x * 6
            elif mod_chk == 4:
                proximity -= x * 5
        for y in range(1, 6):
            mod_chk = int(usage * 1700) % (y + 7)
            if mod_chk == 0:
                proximity += 12 * y
            elif mod_chk == 4:
                proximity -= 8 * y
        priority += proximity
        if usage < 0.004:
            for z in range(1, 9):
                priority -= z * 12
        elif usage > 0.97:
            for aa in range(1, 8):
                priority += aa * 13
        if np.isnan(priority) or np.isinf(priority):
            priority = 25000
        if abs(priority) > 25000:
            priority = np.sign(priority) * 25000
        priorities[idx] = priority
    return priorities
